var src = inputs.Length > 0 ? inputs[0] : null;
var dispMap = inputs.Length > 1 ? inputs[1] : null;
if (src == null)
    return new PixelBuffer(context.TileSize, context.TileSize);

var offsetX = GetFloat(parameters, "offsetX", 0f);
var offsetY = GetFloat(parameters, "offsetY", 0f);
var angle = GetFloat(parameters, "rotationAngle", 0f);
var scaleX = GetFloat(parameters, "scaleX", 1f);
var scaleY = GetFloat(parameters, "scaleY", 1f);
var centerX = GetFloat(parameters, "scaleCenterX", 0.5f);
var centerY = GetFloat(parameters, "scaleCenterY", 0.5f);
var dispStrength = GetFloat(parameters, "displacementStrength", 0f);
var resample = GetChoice(parameters, "resampleMode", "nearest");
var seamless = GetBool(parameters, "seamless", true);

var size = context.TileSize;
var result = new PixelBuffer(size, size);
var angleRad = angle * MathF.PI / 180f;
var cosA = MathF.Cos(angleRad);
var sinA = MathF.Sin(angleRad);
var cx = centerX * size;
var cy = centerY * size;

result.ParallelForEachPixel((x, y) =>
{
    // Apply displacement from displacement map
    float dx = 0, dy = 0;
    if (dispMap != null && dispStrength > 0)
    {
        var (dr, dg, _, _) = dispMap.GetPixel(x, y);
        dx = (dr - 0.5f) * dispStrength * size;
        dy = (dg - 0.5f) * dispStrength * size;
    }

    // Apply offset
    var u = x + offsetX * size + dx;
    var v = y + offsetY * size + dy;

    // Apply rotation and independent X/Y scaling around center
    var rx = u - cx;
    var ry = v - cy;
    // Divide by scale factors separately (undo the scaling)
    var sx = cosA * rx / MathF.Max(0.01f, scaleX) - sinA * ry / MathF.Max(0.01f, scaleY) + cx;
    var sy = sinA * rx / MathF.Max(0.01f, scaleX) + cosA * ry / MathF.Max(0.01f, scaleY) + cy;

    // Sample source at (sx, sy)
    float pr, pg, pb, pa;

    if (resample == "bilinear")
    {
        BilinearSample(src, sx, sy, seamless, size, out pr, out pg, out pb, out pa);
    }
    else
    {
        int si, sj;
        if (seamless)
        {
            si = ((int)MathF.Round(sx) % size + size) % size;
            sj = ((int)MathF.Round(sy) % size + size) % size;
        }
        else
        {
            si = (int)MathF.Round(sx);
            sj = (int)MathF.Round(sy);
        }

        if (si >= 0 && si < size && sj >= 0 && sj < size)
        {
            (pr, pg, pb, pa) = src.GetPixel(si, sj);
        }
        else
        {
            pr = 0; pg = 0; pb = 0; pa = 0;
        }
    }

    result.SetPixel(x, y, pr, pg, pb, pa);
});

return result;


/// <summary>
/// Samples source at floating-point (sx, sy) with bilinear interpolation.
/// Supports seamless wrapping and edge clamping.
/// </summary>
private static void BilinearSample(PixelBuffer src, float sx, float sy, bool seamless, int size,
    out float r, out float g, out float b, out float a)
{
    // Integer pixel coordinates (floor for bilinear quad)
    var ix = (int)MathF.Floor(sx);
    var iy = (int)MathF.Floor(sy);
    var fx = sx - ix;
    var fy = sy - iy;

    // Four corner coordinates
    int x0, y0, x1, y1;
    if (seamless)
    {
        x0 = ((ix % size) + size) % size;
        y0 = ((iy % size) + size) % size;
        x1 = ((ix + 1 % size) + size) % size;
        y1 = ((iy + 1 % size) + size) % size;
    }
    else
    {
        x0 = Math.Clamp(ix, 0, size - 1);
        y0 = Math.Clamp(iy, 0, size - 1);
        x1 = Math.Clamp(ix + 1, 0, size - 1);
        y1 = Math.Clamp(iy + 1, 0, size - 1);
    }

    var (r00, g00, b00, a00) = src.GetPixel(x0, y0);
    var (r10, g10, b10, a10) = src.GetPixel(x1, y0);
    var (r01, g01, b01, a01) = src.GetPixel(x0, y1);
    var (r11, g11, b11, a11) = src.GetPixel(x1, y1);

    // Bilinear interpolation
    var w00 = (1f - fx) * (1f - fy);
    var w10 = fx * (1f - fy);
    var w01 = (1f - fx) * fy;
    var w11 = fx * fy;

    r = r00 * w00 + r10 * w10 + r01 * w01 + r11 * w11;
    g = g00 * w00 + g10 * w10 + g01 * w01 + g11 * w11;
    b = b00 * w00 + b10 * w10 + b01 * w01 + b11 * w11;
    a = a00 * w00 + a10 * w10 + a01 * w01 + a11 * w11;
}
}
